window.LEE_DBP_LEVELS_FROM_FLAGS=(flags)=>{
  const levels=[];
  if(flags?.[0]==="T") levels.push("Tezsiz YL");
  if(flags?.[1]==="T") levels.push("Tezli YL");
  if(flags?.[2]==="D") levels.push("Doktora");
  return levels.length?levels:["Tezli YL"];
};
window.LEE_DBP_PUBLIC_VISIBILITY_KEY="lee-dbp-public-program-visibility";
window.LEE_DBP_PROGRAM_KEY=(row)=>`${row[1]}-${row[2]}`
  .toLocaleLowerCase("tr-TR")
  .replace(/[çÇ]/g,"c").replace(/[ğĞ]/g,"g").replace(/[ıİ]/g,"i")
  .replace(/[öÖ]/g,"o").replace(/[şŞ]/g,"s").replace(/[üÜ]/g,"u")
  .normalize("NFD").replace(/[\u0300-\u036f]/g,"")
  .replace(/[^a-z0-9]+/g,"-").replace(/^-|-$/g,"");
window.LEE_DBP_PROGRAM_LEVEL_KEY=(row,level)=>`${window.LEE_DBP_PROGRAM_KEY(row)}__${String(level||"").toLocaleLowerCase("tr-TR").replace(/\s+/g,"-")}`;
window.LEE_DBP_READ_PUBLIC_VISIBILITY=()=>{
  try{return JSON.parse(localStorage.getItem(window.LEE_DBP_PUBLIC_VISIBILITY_KEY)||"{}")}catch{return {}}
};
window.LEE_DBP_IS_PROGRAM_PUBLIC=(row,visibility=window.LEE_DBP_READ_PUBLIC_VISIBILITY())=>visibility[window.LEE_DBP_PROGRAM_KEY(row)]!==false;
window.LEE_DBP_IS_PROGRAM_LEVEL_PUBLIC=(row,level,visibility=window.LEE_DBP_READ_PUBLIC_VISIBILITY())=>{
  const key=window.LEE_DBP_PROGRAM_LEVEL_KEY(row,level);
  return Object.prototype.hasOwnProperty.call(visibility,key)?visibility[key]!==false:window.LEE_DBP_IS_PROGRAM_PUBLIC(row,visibility);
};
window.LEE_DBP_PUBLIC_LEVELS=(row,visibility=window.LEE_DBP_READ_PUBLIC_VISIBILITY())=>
  window.LEE_DBP_LEVELS_FROM_FLAGS(row?.[3]).filter((level)=>window.LEE_DBP_IS_PROGRAM_LEVEL_PUBLIC(row,level,visibility));
